        # `act push` (which doesn't pass inputs) picks them up via the env
        # fallback expression `github.event.inputs.x || 'default'`.
        $patched = $originalWorkflow `
            -replace "default: fixtures/package\.json",       "default: $($c.VersionFile)" `
            -replace "default: fixtures/commits-feat\.txt",   "default: $($c.CommitsFile)"
        Set-Content -LiteralPath $workflowPath -Value $patched -NoNewline

